#define MAX_PD      (3.0e6f)
#define PRECISION   0.001f
#define AMB_TEMP    80.0f

__kernel void hotspot(const int iteration,
                      __global const float *power,
                      __global float *temp_src,
                      __global float *temp_dst,
                      const int col,
                      const int row,
                      const int borderCols,
                      const int borderRows,
                      const float Cap,
                      const float Rx,
                      const float Ry,
                      const float Rz,
                      const float step)
{
    if (get_global_id(0) != 0 || get_global_id(1) != 0)
        return;

    (void)borderCols;
    (void)borderRows;

    const float step_div_Cap = (step / 1000.0f) / Cap;
    const float Rx_1 = 1.0f / Rx;
    const float Ry_1 = 1.0f / Ry;
    const float Rz_1 = 1.0f / Rz;

    for (int it = 0; it < iteration; ++it) {
        __global float *src = (it & 1) ? temp_dst : temp_src;
        __global float *dst = (it & 1) ? temp_src : temp_dst;

        for (int r = 0; r < row; ++r) {
            int base = r * col;
            for (int c = 0; c < col; ++c) {
                int idx = base + c;
                float center = src[idx];

                float horiz = 0.0f;
                float vert = 0.0f;

                if (c > 0)       horiz += src[idx - 1] - center;
                if (c < col - 1) horiz += src[idx + 1] - center;
                if (r > 0)       vert  += src[idx - col] - center;
                if (r < row - 1) vert  += src[idx + col] - center;

                float delta = step_div_Cap *
                              (power[idx] +
                               horiz * Rx_1 +
                               vert * Ry_1 +
                               (AMB_TEMP - center) * Rz_1);

                dst[idx] = center + delta;
            }
        }
    }

    if ((iteration & 1) == 0) {
        int size = row * col;
        for (int i = 0; i < size; ++i) {
            temp_dst[i] = temp_src[i];
        }
    }
}
